postData:
{"query":"{
      advertisingLinks(orderBy: publishedAt_DESC) {
           href
           id
           label
           company
           leadParameters
           dataHandlingDoc {
              id
              fileName
              url
           }
           displayPosition
           leadFormConfig
           leadModalInfoLabel
           leadModalInfoText
      }
    }"}

{"query":"
      {
        oomAds(first: 50) {
          adZone
          id
          targetUrl
          adPicture {
            id
            url
          }
        }
        oomNativeBanners(first: 1) {
          id
          note
          paidAd
          title
          centerBox {
            id
            bannerContent
            targetUrl
          }
          leftBox {
            id
            bannerContent
            targetUrl
          }
          rightBox {
            id
            bannerContent
            targetUrl
          }
        }
        oomInterstitialBanners(first: 1, orderBy: publishedAt_DESC) {
          id
          adPicture {
            url(transformation: {image: {resize: {fit: max, height: 550, width: 970}}})
          }
          targetUrl
          expiryDate
          interstitialEvent
        }
      }
    "}

{"query":"
    {
      latestUpdates(orderBy: publishDate_DESC, first: 100) {
        id
        type
        segment
        highlighted
        title
        shortDescription
        content {
          content
          imagePosition
          contentAlign
          youtubeVideoId
          image {
            url (
              transformation: {image: {resize: {fit: max, width: 368, height: 200}}}
            )
          }
        }
        buttons {
          label
          primary
          route
          icon
        }
        publishDate
      }
      latestUpdateNotifications(orderBy: publishedAt_DESC, first: 100) {
        id
        type
        linkLabel
        linkRoute
        route
        segment
        description
      }
    }
    "}

{"query":"{
      advertisingLinks(orderBy: publishedAt_DESC) {
           href
           id
           label
           company
           leadParameters
           dataHandlingDoc {
              id
              fileName
              url
           }
           displayPosition
           leadFormConfig
           leadModalInfoLabel
           leadModalInfoText
      }
    }"}
